import{_ as e,o,c as r,a2 as d}from"./chunks/framework.YhErEiPK.js";const h=JSON.parse('{"title":"Configuration Reference","description":"","frontmatter":{},"headers":[],"relativePath":"reference/configuration.md","filePath":"reference/configuration.md"}'),c={name:"reference/configuration.md"};function s(a,t,n,i,u,p){return o(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="configuration-reference" tabindex="-1">Configuration Reference <a class="header-anchor" href="#configuration-reference" aria-label="Permalink to &quot;Configuration Reference&quot;">​</a></h1><h2 id="common-application-properties" tabindex="-1">Common Application Properties <a class="header-anchor" href="#common-application-properties" aria-label="Permalink to &quot;Common Application Properties&quot;">​</a></h2><p>Various properties can be specified inside your <code>application.properties</code> file, inside your <code>application.yml</code> file, or as command line switches.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Property contributions can come from additional jar files on your classpath, so you should not consider this an exhaustive list. Also, you can define your own properties.</p></div><h2 id="stub-runner-properties" tabindex="-1">Stub Runner Properties <a class="header-anchor" href="#stub-runner-properties" aria-label="Permalink to &quot;Stub Runner Properties&quot;">​</a></h2><p>These are the key configuration properties for Stubborn Contract Stub Runner. Note: the <code>spring.cloud.contract.stubrunner.*</code> property names are preserved for backward compatibility.</p><table tabindex="0"><thead><tr><th>Property</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>spring.cloud.contract.stubrunner.ids</code></td><td>—</td><td>Comma-separated list of stubs to download in <code>groupId:artifactId:version:classifier:port</code> format</td></tr><tr><td><code>spring.cloud.contract.stubrunner.repositoryRoot</code></td><td>—</td><td>URL of the repository with stubs</td></tr><tr><td><code>spring.cloud.contract.stubrunner.stubsMode</code></td><td><code>CLASSPATH</code></td><td>Mode for downloading stubs (<code>CLASSPATH</code>, <code>LOCAL</code>, <code>REMOTE</code>)</td></tr><tr><td><code>spring.cloud.contract.stubrunner.deleteStubsAfterTest</code></td><td><code>true</code></td><td>If <code>true</code>, deletes stubs after the test run</td></tr><tr><td><code>spring.cloud.contract.stubrunner.generateStubs</code></td><td><code>false</code></td><td>If <code>true</code>, generates stubs from contracts</td></tr><tr><td><code>spring.cloud.contract.stubrunner.failOnNoStubs</code></td><td><code>true</code></td><td>If <code>true</code>, fails when no stubs are found</td></tr><tr><td><code>spring.cloud.contract.stubrunner.properties</code></td><td>—</td><td>Map with properties that can be passed to custom Stub Downloaders</td></tr><tr><td><code>spring.cloud.contract.stubrunner.httpServerStubConfigurer</code></td><td>—</td><td>Fully qualified class name of <code>HttpServerStubConfigurer</code> implementation</td></tr><tr><td><code>spring.cloud.contract.stubrunner.classifier</code></td><td><code>stubs</code></td><td>Classifier for the stubs artifact</td></tr><tr><td><code>spring.cloud.contract.stubrunner.stubsPerConsumer</code></td><td><code>false</code></td><td>If <code>true</code>, only registers stubs from the stub directory that is named the same as the consumer application</td></tr><tr><td><code>spring.cloud.contract.stubrunner.consumerName</code></td><td>—</td><td>The consumer name to be used when the <code>stubsPerConsumer</code> feature is used</td></tr><tr><td><code>spring.cloud.contract.stubrunner.mappingsOutputFolder</code></td><td>—</td><td>Path to a folder where stub mappings are dumped</td></tr><tr><td><code>spring.cloud.contract.stubrunner.minPort</code></td><td><code>10000</code></td><td>Minimum port at which the stub should start</td></tr><tr><td><code>spring.cloud.contract.stubrunner.maxPort</code></td><td><code>15000</code></td><td>Maximum port at which the stub should start</td></tr></tbody></table><h2 id="verifier-properties" tabindex="-1">Verifier Properties <a class="header-anchor" href="#verifier-properties" aria-label="Permalink to &quot;Verifier Properties&quot;">​</a></h2><p>These are the key configuration properties for Stubborn Contract Verifier (Maven/Gradle plugin):</p><table tabindex="0"><thead><tr><th>Property</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>testMode</code></td><td><code>MockMvc</code></td><td>Test mode: <code>MockMvc</code>, <code>WebTestClient</code>, <code>JaxRsClient</code>, or <code>Explicit</code></td></tr><tr><td><code>testFramework</code></td><td><code>JUNIT</code></td><td>Test framework: <code>JUNIT</code> (JUnit 4), <code>JUNIT5</code>, or <code>SPOCK</code></td></tr><tr><td><code>basePackageForTests</code></td><td><code>sh.stubborn.contract.verifier.tests</code></td><td>Base package for all generated tests</td></tr><tr><td><code>baseClassForTests</code></td><td>—</td><td>Base class for all generated tests</td></tr><tr><td><code>packageWithBaseClasses</code></td><td>—</td><td>Package where all base classes reside</td></tr><tr><td><code>baseClassMappings</code></td><td>—</td><td>List of base class mappings (contract package regex → base class FQN)</td></tr><tr><td><code>contractsDirectory</code></td><td><code>src/test/resources/contracts</code></td><td>Directory that contains contracts</td></tr><tr><td><code>generatedTestSourcesDir</code></td><td><code>$buildDir/generated-test-sources/contracts</code></td><td>Directory for generated test sources</td></tr><tr><td><code>generatedTestResourcesDir</code></td><td>—</td><td>Directory for generated test resources</td></tr><tr><td><code>stubsOutputDir</code></td><td><code>$buildDir/stubs</code></td><td>Directory for generated WireMock stubs</td></tr><tr><td><code>failOnNoContracts</code></td><td><code>true</code></td><td>Throws an exception when no contracts are found</td></tr><tr><td><code>failOnInProgress</code></td><td><code>true</code></td><td>Fails the build if any in-progress contracts are found</td></tr><tr><td><code>incrementalContractTests</code></td><td><code>true</code></td><td>Only generate tests when contracts change</td></tr><tr><td><code>incrementalContractStubs</code></td><td><code>true</code></td><td>Only generate stubs when contracts change</td></tr><tr><td><code>convertToYaml</code></td><td><code>false</code></td><td>Converts all DSLs to YAML format</td></tr><tr><td><code>assertJsonSize</code></td><td><code>false</code></td><td>Checks the size of JSON arrays in generated tests</td></tr><tr><td><code>contractsMode</code></td><td>—</td><td>Mode for downloading contracts (<code>CLASSPATH</code>, <code>LOCAL</code>, <code>REMOTE</code>)</td></tr><tr><td><code>contractDependency</code></td><td>—</td><td>The contract dependency that contains all packaged contracts</td></tr><tr><td><code>contractsPath</code></td><td>—</td><td>Path to the concrete contracts in the JAR with packaged contracts</td></tr><tr><td><code>contractsRepositoryUrl</code></td><td>—</td><td>URL to a repository with the artifacts that have contracts</td></tr><tr><td><code>contractsProperties</code></td><td>—</td><td>Map of properties passed to Stubborn Contract components</td></tr></tbody></table><h2 id="scm-git-properties" tabindex="-1">SCM / Git Properties <a class="header-anchor" href="#scm-git-properties" aria-label="Permalink to &quot;SCM / Git Properties&quot;">​</a></h2><p>These properties configure the Git-based stub downloader (used when <code>contractsRepositoryUrl</code> starts with <code>git://</code>):</p><table tabindex="0"><thead><tr><th>Property</th><th>Description</th></tr></thead><tbody><tr><td><code>git.branch</code></td><td>Branch to use when checking out contracts</td></tr><tr><td><code>git.username</code></td><td>Username for the Git repository</td></tr><tr><td><code>git.password</code></td><td>Password for the Git repository</td></tr><tr><td><code>git.no-of-attempts</code></td><td>Number of retries for Git operations</td></tr><tr><td><code>git.wait-between-attempts</code></td><td>Wait time (ms) between retries</td></tr></tbody></table><p>These can be set via <code>contractsProperties</code> in Maven/Gradle, or as system properties/environment variables.</p><h2 id="full-configuration-properties-list" tabindex="-1">Full Configuration Properties List <a class="header-anchor" href="#full-configuration-properties-list" aria-label="Permalink to &quot;Full Configuration Properties List&quot;">​</a></h2><p>For the complete list of auto-configured properties, see the auto-generated configuration properties documentation or use the Spring Boot Actuator&#39;s <code>/actuator/configprops</code> endpoint (in development only).</p><p>Common property prefixes:</p><ul><li><code>spring.cloud.contract.stubrunner.*</code> — Stub Runner configuration</li><li><code>spring.cloud.contract.verifier.*</code> — Verifier HTTP port configuration</li></ul>',18)])])}const f=e(c,[["render",s]]);export{h as __pageData,f as default};
